"use client";
import { useState } from "react";
import Link from "next/link";

export default function RegisterPage() {
  const [name, setName] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    // ตรวจสอบความถูกต้องของรหัสผ่าน
    if (password !== confirmPassword) {
      alert("ข้อผิดพลาด: รหัสผ่านและการยืนยันรหัสผ่านไม่ตรงกัน กรุณาตรวจสอบอีกครั้ง");
      return;
    }

    // จำลองการส่งข้อมูลเข้าสู่ระบบ
    alert(`ดำเนินการสำเร็จ: ระบบได้รับข้อมูลการลงทะเบียนของท่าน ${name} เรียบร้อยแล้ว`);
  };

  return (
    <section className="container" style={{ maxWidth: '500px', marginTop: '50px' }}>
      <div className="card">
        <h1 style={{ textAlign: 'center', marginBottom: '10px' }}>ลงทะเบียนเข้าใช้งานระบบ</h1>
        <p className="muted" style={{ textAlign: 'center', marginBottom: '30px' }}>
          กรุณากรอกข้อมูลส่วนบุคคลเพื่อสร้างบัญชีผู้ใช้งาน Medi-Tap
        </p>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <div>
            <label style={{ fontWeight: '600', fontSize: '14px', color: 'var(--text-main)' }}>ชื่อ-นามสกุล (Full Name)</label>
            <input 
              type="text" 
              placeholder="ระบุชื่อและนามสกุลของท่าน" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              required 
            />
          </div>

          <div>
            <label style={{ fontWeight: '600', fontSize: '14px', color: 'var(--text-main)' }}>ชื่อบัญชีผู้ใช้งาน (Username)</label>
            <input 
              type="text" 
              placeholder="กำหนดชื่อบัญชีสำหรับเข้าสู่ระบบ" 
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required 
            />
          </div>

          <div>
            <label style={{ fontWeight: '600', fontSize: '14px', color: 'var(--text-main)' }}>รหัสผ่าน (Password)</label>
            <input 
              type="password" 
              placeholder="กำหนดรหัสผ่าน (อย่างน้อย 4 ตัวอักษร)" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required 
              minLength={4}
            />
          </div>

          <div>
            <label style={{ fontWeight: '600', fontSize: '14px', color: 'var(--text-main)' }}>ยืนยันรหัสผ่าน (Confirm Password)</label>
            <input 
              type="password" 
              placeholder="ระบุรหัสผ่านอีกครั้งเพื่อยืนยัน" 
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required 
              minLength={4}
            />
          </div>

          <button type="submit" className="btn" style={{ marginTop: '15px', width: '100%', padding: '12px', fontSize: '16px' }}>
            ยืนยันการลงทะเบียน
          </button>
        </form>

        <div style={{ textAlign: 'center', marginTop: '20px', fontSize: '14px' }}>
          <span className="muted">หากท่านมีบัญชีผู้ใช้งานแล้ว </span>
          <Link href="/login" style={{ color: 'var(--primary)', fontWeight: 'bold', textDecoration: 'none' }}>
            คลิกเพื่อเข้าสู่ระบบ
          </Link>
        </div>
      </div>
    </section>
  );
}